const EyeIcon=()=><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>;
const SMS_VARS=["jmeno","datum","cas","sluzba","salon","telefon"];
const SMS_VARS_LINK=[...SMS_VARS,"link"];
