    return <input key={i} value={p} onChange={e=>{const np=[...parts];np[i]=e.target.value;onChange(np.join(""));}} style={{border:"none",outline:"none",background:"transparent",fontSize:12,fontFamily:F,padding:"2px 0",minWidth:Math.max(16,p.length*7.5),width:Math.max(16,p.length*7.5),flexShrink:1,flexGrow:0}}/>;
