function BarChart({data,labels,color="#c9956b",height=130}){const max=Math.max(...data,1);return (<div style={{display:"flex",alignItems:"flex-end",gap:8,height,padding:"0 4px"}}>{data.map((v,i)=><div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:3}}><span style={{fontSize:9,fontWeight:600,color:"#6b5d4f"}}>{v>0?fCZK(v):""}</span><div style={{width:"100%",borderRadius:"6px 6px 0 0",background:v>0?`linear-gradient(180deg,${color},${color}88)`:"#f0e8de",height:`${Math.max((v/max)*100,4)}%`,minHeight:4,transition:"height 0.3s"}}/><span style={{fontSize:10,color:"#8a7b6b"}}>{labels[i]}</span></div>)}</div>);}
function getAvailableSlots(dayBookings,needed,cancelledIds,dayHours){
  if(!dayHours||!dayHours.open)return[];
  const wS=toMin(dayHours.start),wE=toMin(dayHours.end)+20;
  const busy=dayBookings.filter(b=>b.status!=="cancelled"&&!cancelledIds.includes(b.id)).map(b=>({s:toMin(b.time),e:toMin(b.time)+(b.duration||60)}));
  if(dayHours.hasBreak&&dayHours.breakStart&&dayHours.breakEnd)busy.push({s:toMin(dayHours.breakStart),e:toMin(dayHours.breakEnd)});
  busy.sort((a,b)=>a.s-b.s);const slots=[];for(let t=wS;t+needed<=wE;t+=15){const e=t+needed;if(!busy.some(b=>t<b.e&&e>b.s))slots.push(fromMin(t));}return slots;
}
const normalizePhone=raw=>{let p=raw.replace(/[\s\-()]/g,"");if(/^\d{9}$/.test(p))return "+420"+p;if(/^00/.test(p))return "+"+p.slice(2);if(/^\+/.test(p))return p;if(/^420\d{9}$/.test(p))return "+"+p;return "+420"+p;};
