  const gDH=ds=>{const[y,m,d]=ds.split("-").map(Number);const dow=new Date(y,m-1,d).getDay();return hours.find(h=>h.day===dow);};
  const slots=useMemo(()=>{if(!sDate||tDur===0)return[];const all=getAvailableSlots(bookings.filter(b=>b.date===sDate),tDur,cancelledIds,gDH(sDate));const now=new Date();const todayLocal=now.getFullYear()+"-"+String(now.getMonth()+1).padStart(2,"0")+"-"+String(now.getDate()).padStart(2,"0");if(sDate===todayLocal){const minTime=now.getHours()*60+now.getMinutes()+120;return all.filter(s=>toMin(s)>=minTime);}return all;},[sDate,tDur,bookings,cancelledIds,hours]);
