            <button onClick={()=>{const now=new Date(TODAY);const flt=sales.filter(s=>{if(!s.date)return billPeriod==="day";if(billPeriod==="day")return s.date===TODAY;if(billPeriod==="week"){const d=new Date(s.date);return(now-d)/(864e5)<7;}if(billPeriod==="month"){const d=new Date(s.date);return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();}return true;});const csv="\uFEFF"+[t.dateCol,t.time,t.client,t.serviceCol,t.transSvc,t.transProd,t.transComm,t.transNet,t.transMethod].join(";")+"\n"+flt.map(s=>{const cm=Math.round((s.svcAmt||0)*(commRate/100));return[s.dateStr||"",s.time,s.client,'"'+(s.services||"")+'"',s.svcAmt||0,s.prodAmt||0,cm,(s.svcAmt||0)-cm+(s.prodAmt||0),s.method==="K"?"Karta":"Hotovost"].join(";");}).join("\n");const b=new Blob([csv],{type:"text/csv;charset=utf-8"});const u=URL.createObjectURL(b);const a=document.createElement("a");a.href=u;a.download="vyuctovani.csv";a.click();URL.revokeObjectURL(u);}} style={{padding:"5px 12px",borderRadius:8,border:"none",background:"linear-gradient(135deg,#155724,#28a745)",color:"#fff",fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:F}}>📊 {t.exportXls}</button>
